mapper.select:
/* wms-outbound-obpckgprcs-sql-oracle.xml - selectCntrWkDivCd - 포장처리 - 피킹용기 작업구분코드 조회 */
SELECT CNTR.CNTRWKDIVCD
  FROM TWORK_MST_CNTR CNTR
 WHERE CNTR.CTKEY = COALESCE(#{ctkey}, #{sctkey})
   AND CNTR.CNTRBARCODE = #{cntrbarcode}

/* wms-outbound-obpckgprcs-sql-oracle.xml - selectObHdByPkCntrBarcode - 릴리즈정보 조회 BY 피킹용기 */ SELECT CNTR.PIHDKEY ,CNTR.CNTRBARCODE ,CNTR.WKTYPECD FROM ( SELECT PC.PIHDKEY , PC.CNTRBARCODE , WAHD.WKTYPECD , ROW_NUMBER () OVER(ORDER BY PC.INSERTDATE DESC) AS RN FROM TWORK_INFO_PK_CNTR PC INNER JOIN TWORK_MST_CNTR CNTR ON PC.CTKEY = CNTR.CTKEY AND PC.CNTRBARCODE = CNTR.CNTRBARCODE INNER JOIN TWORK_INFO_PI_HD PIHD ON PC.CTKEY = PIHD.CTKEY AND PC.OWKEY = PIHD.OWKEY AND PC.PIHDKEY = PIHD.PIHDKEY INNER JOIN TWORK_INFO_WA_HD WAHD ON PIHD.CTKEY = WAHD.CTKEY AND PIHD.OWKEY = WAHD.OWKEY AND PIHD.PIHDKEY = WAHD.PIHDKEY WHERE PC.CTKEY = COALESCE(#{ctkey}, #{sctkey}) AND PC.OWKEY = COALESCE(#{owkey}, #{sowkey}) AND PC.CNTRBARCODE = #{cntrbarcode}
AND PC.PIHDKEY = #{pihdkey}
AND PC.CNTRDDLNYN = 'Y' AND WAHD.WAWKSTATUSCD IN ('50','60') /*50: 작업중. 60:작업완료 웨이브 내에서 사용중인 분류토트 */ AND WAHD.WKTYPECD IN ('PW', 'UW') /*덕용,단포*/ AND CNTR.CNTRDIVCD IN ('10', '20', '60') /*10:PLT 20:TOTE 60:롤테이너*/ AND CNTR.CNTRWKDIVCD = 10 /*10: 피킹용*/ ) CNTR WHERE RN = 1

/* wms-outbound-obpckgprcs-sql-oracle.xml - selectObHdByObhdkeyOrWblno - 릴리즈정보 조회 BY 릴리즈코드OR운송장번호 */ SELECT OBHD.OBHDKEY ,OBHD.WKTYPECD FROM ( SELECT OH.CTKEY ,OH.OWKEY ,OH.OBHDKEY ,OH.OBSTATUSCD ,CASE WHEN OH.WKTYPECD IS NULL THEN (CASE WHEN OH.ORDSEPTYPECD = '10' THEN 'UW' ELSE 'DW' END) ELSE OH.WKTYPECD END AS WKTYPECD ,(CASE WHEN OH.PIHDKEY IS NULL THEN (SELECT PIHDKEY FROM TWORK_INFO_OB_HD WHERE CTKEY = OH.CTKEY AND OWKEY = OH.OWKEY AND OBHDKEY = OH.PKOBHDKEY) ELSE OH.PIHDKEY END) AS PIHDKEY FROM TWORK_INFO_OB_HD OH LEFT OUTER JOIN TWORK_INFO_OB_NIS_HD NISHD ON OH.CTKEY = NISHD.CTKEY AND OH.OWKEY = NISHD.OWKEY AND OH.OBHDKEY = NISHD.OBHDKEY WHERE OH.CTKEY = COALESCE(#{ctkey}, #{sctkey}) AND OH.OWKEY = COALESCE(#{owkey}, #{sowkey})
AND OH.OBHDKEY = #{obhdkey}
AND (OH.OBHDKEY = #{obhdkeywblno} OR OH.WBLNO = #{obhdkeywblno} OR NISHD.OBNISNO = #{obhdkeywblno})
) OBHD INNER JOIN TWORK_INFO_PI_HD PIHD ON OBHD.CTKEY = PIHD.CTKEY AND OBHD.OWKEY = PIHD.OWKEY AND OBHD.PIHDKEY = PIHD.PIHDKEY WHERE ( (PIHD.PKDIVCD = '10' AND OBHD.OBSTATUSCD IN ('25','30','85')) /*오더별피킹 - 25: 부분피킹 30 : 피킹확정 ,85: 결품처리확정 (헤더만사용) */ OR (PIHD.PKDIVCD IN ('20','30') AND OBHD.WKTYPECD = 'RW' AND OBHD.OBSTATUSCD IN ('20', '85')) /*총량피킹,통합피킹/로봇작업 - 20: 피킹지시, 85: 결품처리확정 */ OR (PIHD.PKDIVCD IN ('20','30') AND OBHD.WKTYPECD = 'DW' AND OBHD.OBSTATUSCD IN ('40','85')) /*총량피킹,통합피킹/DAS작업 - 40: 미패킹, 85: 결품처리확정 */ OR (PIHD.PKDIVCD = '20' AND OBHD.WKTYPECD IN ('UW','PW') AND OBHD.OBSTATUSCD IN ('25','30','85')) /*총량피킹/단포,덕용작업 - 25: 부분피킹, 30:피킹화정, 85: 결품처리확정 */ )

