mapper.sql:
/* wms-outbound-obpckgprcs-sql-oracle.xml - selectSinglePckgIcSql - 포장처리 - 단포 상품정보 SQL */ WITH OBHD AS ( SELECT OBHD.CTKEY , OBHD.OWKEY , OBHD.OBHDKEY , OBHD.WKTYPECD , OBHD.PIHDKEY FROM TWORK_INFO_OB_HD OBHD INNER JOIN TWORK_INFO_OB_DT OBDT ON OBHD.CTKEY = OBDT.CTKEY AND OBHD.OWKEY = OBDT.OWKEY AND OBHD.OBHDKEY = OBDT.OBHDKEY
INNER JOIN TWORK_INFO_PI_DT PIDT ON OBDT.CTKEY = PIDT.CTKEY AND OBDT.OWKEY = PIDT.OWKEY AND OBDT.OBHDKEY = PIDT.OBHDKEY AND OBDT.OBDTKEY = PIDT.OBDTKEY LEFT OUTER JOIN TWORK_INFO_PK_CNTR_DT PCDT ON PIDT.CTKEY = PCDT.CTKEY AND PIDT.OWKEY = PCDT.OWKEY AND PIDT.PIHDKEY = PCDT.PIHDKEY AND PIDT.PIDTKEY = PCDT.PIDTKEY LEFT OUTER JOIN TWORK_INFO_PK_CNTR PC ON PCDT.CTKEY = PC.CTKEY AND PCDT.OWKEY = PC.OWKEY AND PCDT.PIHDKEY = PC.PIHDKEY AND PCDT.CNTRBARCODE = PC.CNTRBARCODE
WHERE OBHD.CTKEY = COALESCE(#{ctkey}, #{sctkey}) AND OBHD.OWKEY = COALESCE(#{owkey}, #{sowkey})
AND OBHD.OBHDKEY = #{obhdkey}
AND PC.CNTRDDLNYN = 'Y' AND PC.PIHDKEY = #{pihdkey} AND PC.CNTRBARCODE = #{cntrbarcode}
GROUP BY OBHD.CTKEY , OBHD.OWKEY , OBHD.OBHDKEY , OBHD.WKTYPECD , OBHD.PIHDKEY ), NEWOBHD AS ( SELECT NEWOBHD.CTKEY ,NEWOBHD.OWKEY ,NEWOBHD.OBHDKEY ,NEWOBHD.WKTYPECD ,NEWOBHD.PIHDKEY FROM OBHD INNER JOIN TWORK_INFO_OB_HD NEWOBHD ON OBHD.CTKEY = NEWOBHD.CTKEY AND OBHD.OWKEY = NEWOBHD.OWKEY AND OBHD.OBHDKEY = NEWOBHD.PKOBHDKEY ) SELECT IC.ICKEY , ICB.BARCODE , IC.ICNM /*상품명*/ , IC.CUSHNMEPCKGYN /*완충재포장여부*/ , IC.DNGMGMTYN /*위험물관리여부*/ , IC.IMGURL /*상품이미지URL*/ , MAX(OBINFO.PIHDKEY) AS PIHDKEY , OBINFO.CTKEY , OBINFO.OWKEY , SUM(OBDT.EXPCTQTY) AS EXPCTQTY /*예정수량 총합*/ , SUM(OBDT.INITQTY) - SUM(OBDT.CNFRMQTY) - SUM(OBDT.NISQTY) - SUM(CASE OBDT.OBDTSTATUSCD WHEN '97' THEN OBDT.EXPCTQTY ELSE 0 END) AS NONCNFRMQTY /*잔여수량 총합*/ FROM ( SELECT CTKEY, OWKEY, OBHDKEY, WKTYPECD, PIHDKEY FROM OBHD UNION SELECT CTKEY, OWKEY, OBHDKEY, WKTYPECD, PIHDKEY FROM NEWOBHD ) OBINFO INNER JOIN TWORK_INFO_OB_DT OBDT ON OBINFO.CTKEY = OBDT.CTKEY AND OBINFO.OWKEY = OBDT.OWKEY AND OBINFO.OBHDKEY = OBDT.OBHDKEY INNER JOIN TWORK_MST_IC IC /*상품 마스터*/ ON OBDT.CTKEY = IC.CTKEY AND OBDT.OWKEY = IC.OWKEY AND OBDT.ICKEY = IC.ICKEY LEFT OUTER JOIN TWORK_MST_ICBARCODE ICB /*상품바코드 마스터*/ ON IC.CTKEY = ICB.CTKEY AND IC.OWKEY = ICB.OWKEY AND IC.ICKEY = ICB.ICKEY AND ICB.UOM = (CASE WHEN OBINFO.WKTYPECD = 'PW' THEN 'CTN' ELSE 'EA' END) GROUP BY IC.ICKEY /*상품코드*/ , ICB.BARCODE /*바코드*/ , IC.ICNM /*상품명*/ , IC.CUSHNMEPCKGYN /*완충재포장여부*/ , IC.DNGMGMTYN /*위험물관리여부*/ , IC.IMGURL /*상품이미지URL*/ , OBINFO.CTKEY , OBINFO.OWKEY ORDER BY IC.ICKEY /*상품코드*/

