mapper.sql:
/* wms-outbound-obpckgprcs-sql-oracle.xml - selectSinglePckgObSql - 포장처리 - 단포 출고정보 SQL */ WITH OBHD AS ( SELECT OBHD.CTKEY ,OBHD.OWKEY ,OBHD.OBHDKEY FROM TWORK_INFO_OB_HD OBHD /*출고 공통정보*/ INNER JOIN TWORK_INFO_OB_DT OBDT /*출고 상세정보*/ ON OBHD.CTKEY = OBDT.CTKEY AND OBHD.OWKEY = OBDT.OWKEY AND OBHD.OBHDKEY = OBDT.OBHDKEY
INNER JOIN TWORK_INFO_PI_DT PIDT ON OBDT.CTKEY = PIDT.CTKEY AND OBDT.OWKEY = PIDT.OWKEY AND OBDT.OBHDKEY = PIDT.OBHDKEY AND OBDT.OBDTKEY = PIDT.OBDTKEY LEFT OUTER JOIN TWORK_INFO_PK_CNTR_DT PCDT ON PIDT.CTKEY = PCDT.CTKEY AND PIDT.OWKEY = PCDT.OWKEY AND PIDT.PIHDKEY = PCDT.PIHDKEY AND PIDT.PIDTKEY = PCDT.PIDTKEY LEFT OUTER JOIN TWORK_INFO_PK_CNTR PC ON PCDT.CTKEY = PC.CTKEY AND PCDT.OWKEY = PC.OWKEY AND PCDT.PIHDKEY = PC.PIHDKEY AND PCDT.CNTRBARCODE = PC.CNTRBARCODE
WHERE OBHD.CTKEY = #{ctkey} AND OBHD.OWKEY = #{owkey} AND OBDT.ICKEY = #{ickey} AND OBHD.OBSTATUSCD IN ('25', '30', '65', '70', '80', '85', '97') /* 부분피킹, 피킹확정, 부분출고, 출고완료, 결품보류, 결품보류확정, 작업취소 */
AND OBHD.OBHDKEY = #{obhdkey}
AND PC.CNTRDDLNYN = 'Y' AND PC.PIHDKEY = #{pihdkey} AND PC.CNTRBARCODE = #{cntrbarcode}
GROUP BY OBHD.CTKEY ,OBHD.OWKEY ,OBHD.OBHDKEY ), NEWOBHD AS ( SELECT NEWOBHD.CTKEY ,NEWOBHD.OWKEY ,NEWOBHD.OBHDKEY FROM OBHD INNER JOIN TWORK_INFO_OB_HD NEWOBHD ON OBHD.CTKEY = NEWOBHD.CTKEY AND OBHD.OWKEY = NEWOBHD.OWKEY AND OBHD.OBHDKEY = NEWOBHD.PKOBHDKEY ) SELECT OBHD.CTKEY /*센터코드*/ , OBHD.OWKEY /*화주코드*/ , OBHD.OBHDKEY /*릴리즈코드*/ , OBHD.PREOBHDKEY /*이전 릴리즈코드*/ , OBHD.WBLNO /*운송장번호*/ , OBHD.OBSTATUSCD /*출고상태*/ , OBDT.OBDTKEY /*릴리즈상세코드*/ , OBDT.OBDTSTATUSCD /*출고상세 상태코드*/ , OBDT.ICKEY /*상품코드*/ , OBDT.INITQTY /*초기수량*/ , OBDT.EXPCTQTY /*예정수량*/ , OBDT.PKQTY /*피킹수량*/ , OBDT.PAKQTY /*패킹완료수량*/ , OBDT.CNFRMQTY /*확정수량*/ , COALESCE(NISDT.NISQTY, 0) AS NISQTY /*결품수량*/ , CASE WHEN OBHD.OBSTATUSCD = '50' THEN OBDT.PAKQTY WHEN OBHD.OBSTATUSCD IN ('60', '65', '70') THEN OBDT.CNFRMQTY ELSE COALESCE(NISDT.CNFRMQTY, OBDT.PKQTY) END AS TOPAKQTY /*검수수량(출고수량화면입력값)*/ , 0 AS SEPQTY /*분리수량(박스추가시 사용)*/ , OBHD.DLVRYCORPCD , DLV.DLVRYCORPNM /*택배사*/ , RBOX.BOXNM AS RECOMBOXNM /*추천박스*/ , OBHD.PCKGBOXBARCODE AS PAKBOXBARCODE /*포장박스*/ , CASE WHEN OBHD.OBSTATUSCD IN ('25', '30', '40', '85') THEN 'Y' ELSE 'N' END EDTBOXBARCODEYN , CASE WHEN MAX(PRHS.PRSEQ) > 0 THEN 'Y' ELSE 'N' END PRSEQYN , CASE WHEN OBHD.OBSTATUSCD IN ('25', '30', '40') THEN 'Y' ELSE 'N' END TOPAKEDITYN /*출고수량 편집가능여부 20:피킹지시, 25: 부분피킹, 30: 피킹확정, 40: 미패킹*/ , OBHD.WKCNLREQYN /*작업취소요청여부*/ , CASE WHEN MIN(PIDT.PKDTWKSTATUSCD) = '00' THEN 'Y' ELSE 'N' END NONPICKINGYN FROM ( SELECT CTKEY ,OWKEY ,OBHDKEY FROM OBHD UNION SELECT CTKEY ,OWKEY ,OBHDKEY FROM NEWOBHD ) OBINFO INNER JOIN TWORK_INFO_OB_HD OBHD ON OBINFO.CTKEY = OBHD.CTKEY AND OBINFO.OWKEY = OBHD.OWKEY AND OBINFO.OBHDKEY = OBHD.OBHDKEY INNER JOIN TWORK_INFO_OB_DT OBDT /*출고 상세정보*/ ON OBHD.CTKEY = OBDT.CTKEY AND OBHD.OWKEY = OBDT.OWKEY AND OBHD.OBHDKEY = OBDT.OBHDKEY LEFT OUTER JOIN TWORK_INFO_PI_DT PIDT ON OBDT.CTKEY = PIDT.CTKEY AND OBDT.OWKEY = PIDT.OWKEY AND OBDT.OBHDKEY = PIDT.OBHDKEY AND OBDT.OBDTKEY = PIDT.OBDTKEY INNER JOIN TWORK_MST_DLVRYCORP DLV /*택배사 마스터*/ ON OBHD.CTKEY = DLV.CTKEY AND OBHD.OWKEY = DLV.OWKEY AND OBHD.DLVRYCORPCD = DLV.DLVRYCORPCD AND DLV.DELYN = 'N' LEFT OUTER JOIN TWORK_MST_BOX RBOX /*박스마스터(추천)*/ ON OBHD.CTKEY = RBOX.CTKEY AND OBHD.RECOMBOXBARCODE = RBOX.BOXBARCODE LEFT OUTER JOIN TWORK_MST_BOX PBOX /*박스마스터(포장)*/ ON OBHD.CTKEY = PBOX.CTKEY AND OBHD.PCKGBOXBARCODE = PBOX.BOXBARCODE LEFT OUTER JOIN TWORK_INFO_OB_NIS_HD NISHD /*출고 결품 헤더 정보*/ ON OBHD.CTKEY = NISHD.CTKEY AND OBHD.OWKEY = NISHD.OWKEY AND OBHD.OBHDKEY = NISHD.OBHDKEY LEFT OUTER JOIN TWORK_INFO_OB_NIS_DT NISDT /*출고 결품 상세 정보*/ ON NISHD.CTKEY = NISDT.CTKEY AND NISHD.OWKEY = NISDT.OWKEY AND NISHD.OBNISNO = NISDT.OBNISNO AND OBDT.OBDTKEY = NISDT.OBDTKEY LEFT OUTER JOIN TWORK_INFO_WBL_PRHS PRHS /*운송장 출력 이력 정보*/ ON OBHD.CTKEY = PRHS.CTKEY AND OBHD.OWKEY = PRHS.OWKEY AND OBHD.DLVRYCORPCD = PRHS.DLVRYCORPCD AND OBHD.WBLNO = PRHS.WBLNO AND OBHD.OBHDKEY = PRHS.OBHDKEY GROUP BY OBHD.CTKEY /*센터코드*/ , OBHD.OWKEY /*화주코드*/ , OBHD.OBHDKEY /*릴리즈코드*/ , OBHD.PREOBHDKEY /*이전 릴리즈코드*/ , OBHD.WBLNO /*운송장번호*/ , OBHD.OBSTATUSCD /*출고상태*/ , OBDT.OBDTKEY /*릴리즈상세코드*/ , OBDT.OBDTSTATUSCD /*출고상세 상태코드*/ , OBDT.ICKEY /*상품코드*/ , OBDT.INITQTY /*초기수량*/ , OBDT.EXPCTQTY /*예정수량*/ , OBDT.PKQTY /*피킹수량*/ , OBDT.PAKQTY /*패킹완료수량*/ , OBDT.CNFRMQTY /*확정수량*/ , NISDT.NISQTY /*결품수량*/ , CASE WHEN OBHD.OBSTATUSCD = '50' THEN OBDT.PAKQTY WHEN OBHD.OBSTATUSCD IN ('60', '65', '70') THEN OBDT.CNFRMQTY ELSE COALESCE(NISDT.CNFRMQTY, OBDT.PKQTY) END /*검수수량(출고수량화면입력값)*/ , OBHD.DLVRYCORPCD , DLV.DLVRYCORPNM /*택배사*/ , RBOX.BOXNM /*추천박스*/ , PBOX.BOXNM /*포장박스*/ , OBHD.PCKGBOXBARCODE , OBHD.WKCNLREQYN /*작업취소요청여부*/ , OBHD.PKOBHDKEY ORDER BY MAX(OBDT.PKQTY) OVER (PARTITION BY COALESCE(OBHD.PKOBHDKEY, OBHD.OBHDKEY)) DESC , COALESCE(OBHD.PKOBHDKEY, OBHD.OBHDKEY) , OBHD.OBHDKEY , OBDT.PKQTY DESC

