/* wms-outbound-obpckgprcs-sql-oracle.xml - selectSinglePckgObComplInfo - 포장처리 - 단포 출고완료 여부 조회 */ WITH OBHD AS ( SELECT OBHD.CTKEY ,OBHD.OWKEY ,OBHD.OBHDKEY FROM TWORK_INFO_OB_HD OBHD /*출고 공통정보*/ INNER JOIN TWORK_INFO_OB_DT OBDT /*출고 상세정보*/ ON OBHD.CTKEY = OBDT.CTKEY AND OBHD.OWKEY = OBDT.OWKEY AND OBHD.OBHDKEY = OBDT.OBHDKEY LEFT OUTER JOIN TWORK_INFO_PI_DT PIDT ON OBDT.CTKEY = PIDT.CTKEY AND OBDT.OWKEY = PIDT.OWKEY AND OBDT.OBHDKEY = PIDT.OBHDKEY AND OBDT.OBDTKEY = PIDT.OBDTKEY LEFT OUTER JOIN TWORK_INFO_PK_CNTR_DT PCDT ON PIDT.CTKEY = PCDT.CTKEY AND PIDT.OWKEY = PCDT.OWKEY AND PIDT.PIHDKEY = PCDT.PIHDKEY AND PIDT.PIDTKEY = PCDT.PIDTKEY LEFT OUTER JOIN TWORK_INFO_PK_CNTR PC ON PCDT.CTKEY = PC.CTKEY AND PCDT.OWKEY = PC.OWKEY AND PCDT.PIHDKEY = PC.PIHDKEY AND PCDT.CNTRBARCODE = PC.CNTRBARCODE WHERE OBHD.CTKEY = #{ctkey} AND OBHD.OWKEY = #{owkey} AND OBHD.OBSTATUSCD IN ('25', '30', '40', '45', '50', '60', '65', '70', '80', '85', '97') /* 부분피킹, 피킹확정, 미패킹, 부분패킹, 패킹완료, 미출고, 부분출고, 출고완료, 결품보류, 결품보류확정, 작업취소 */
AND OBHD.OBHDKEY = #{obhdkey}
AND PC.CNTRDDLNYN = 'Y' AND PC.PIHDKEY = #{pihdkey} AND PC.CNTRBARCODE = #{cntrbarcode}
GROUP BY OBHD.CTKEY ,OBHD.OWKEY ,OBHD.OBHDKEY ), NEWOBHD AS ( SELECT NEWOBHD.CTKEY ,NEWOBHD.OWKEY ,NEWOBHD.OBHDKEY FROM OBHD INNER JOIN TWORK_INFO_OB_HD NEWOBHD ON OBHD.CTKEY = NEWOBHD.CTKEY AND OBHD.OWKEY = NEWOBHD.OWKEY AND OBHD.OBHDKEY = NEWOBHD.PKOBHDKEY ) SELECT CASE WHEN COUNT(OH.OBHDKEY) = SUM(CASE WHEN OH.OBSTATUSCD IN ('60', '65', '70', '80') THEN 1 ELSE 0 END) THEN 'Y' ELSE 'N' END AS COMPLYN FROM TWORK_INFO_OB_HD OH INNER JOIN (SELECT CTKEY ,OWKEY ,OBHDKEY FROM OBHD UNION SELECT CTKEY ,OWKEY ,OBHDKEY FROM NEWOBHD) OBINFO ON OH.CTKEY = OBINFO.CTKEY AND OH.OWKEY = OBINFO.OWKEY AND OH.OBHDKEY = OBINFO.OBHDKEY

