mapper.insert:
/* wms-outbound-obpckgprcs-sql-oracle.xml - insertObNisHd - 포장처리 - 출고 결품보류 헤더 등록 */
INSERT INTO TWORK_INFO_OB_NIS_HD /*출고 결품 헤더 정보*/
(	   CTKEY        /*센터 코드*/
	 , OWKEY        /*화주 코드*/
	 , OBNISNO      /*출고 결품 번호*/
	 , OBHDKEY      /*릴리즈 코드*/
	 , STNBARCODE   /*스테이션 바코드*/
	 , INSERTDATE   /*입력 일시*/
	 , INSERTURKEY  /*입력자*/
	 , UPDATEDATE   /*수정 일시*/
	 , UPDATEURKEY  /*수정자*/
) VALUES (
	   #{ctkey}
	 , #{owkey}
	 , #{obnisno}
	 , #{obhdkey}
	 , #{pakstnbarcode}
	 , #{sysdate}
	 , #{surkey}
	 , #{sysdate}
	 , #{surkey}
)

/* wms-outbound-obpckgprcs-sql-oracle.xml - insertObNisDt - 포장처리 - 출고 결품보류 상세 등록 */
INSERT INTO TWORK_INFO_OB_NIS_DT /*출고 결품 상세 정보*/
(	   CTKEY         /*센터 코드*/
	 , OWKEY         /*화주 코드*/
	 , OBNISNO       /*출고 결품 번호*/
	 , OBNISDTNO     /*출고 결품 상세 번호*/
	 , OBHDKEY       /*릴리즈 코드*/
	 , OBDTKEY       /*릴리즈 상세 코드*/
	 , ICKEY		 /*상품 코드*/
	 , EXPCTQTY      /*예정 수량*/
	 , NISQTY        /*결품 수량*/
	 , CNFRMQTY      /*확정 수량*/
	 , NISPRCSSTATUSCD /*결품 처리 상태 코드*/
     , PKIMPSYN      /*피킹 불가 여부*/
	 , INSERTDATE    /*입력 일시*/
	 , INSERTURKEY   /*입력자*/
	 , UPDATEDATE    /*수정 일시*/
	 , UPDATEURKEY   /*수정자*/
) VALUES (
	   #{ctkey}
	 , #{owkey}
	 , #{obnisno}
	 , #{obnisdtno}
	 , #{obhdkey}
	 , #{obdtkey}
	 , #{ickey}
	 , #{expctqty}
	 , #{nisqty}
	 , #{pakqty}
	 , #{nisprcsstatuscd}
	 , #{pkimpsyn}
	 , #{sysdate}
	 , #{surkey}
	 , #{sysdate}
	 , #{surkey}
)

mapper.update:
/* wms-outbound-obpckgprcs-sql-oracle.xml - updateOutboundHeaderStatusCdByNisHold - 릴리즈코드 상태 변경 BY 결품보류 */
UPDATE TWORK_INFO_OB_HD
   SET OBSTATUSCD = #{obstatuscd}
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND OBHDKEY = #{obhdkey}

mapper.select:
/* wms-outbound-obpckgprcs-sql-oracle.xml - selectWkCntrInfoOnPop - 포장처리 - 작업용기 조회(팝업) */ SELECT WH.WAHDDAY , WH.WAHDNM , CD.CTCDDTNM , PC.CNTRBARCODE , PC.PIHDKEY , SUM(PCD.PKQTY) AS PKQTY FROM TWORK_INFO_WA_HD WH INNER JOIN TWORK_INFO_PI_HD PH ON WH.CTKEY = PH.CTKEY AND WH.OWKEY = PH.OWKEY AND WH.PIHDKEY = PH.PIHDKEY INNER JOIN TWORK_INFO_PI_DT PD ON PH.CTKEY = PD.CTKEY AND PH.OWKEY = PD.OWKEY AND PH.PIHDKEY = PD.PIHDKEY INNER JOIN TWORK_INFO_PK_CNTR PC ON PH.CTKEY = PC.CTKEY AND PH.OWKEY = PC.OWKEY AND PH.PIHDKEY = PC.PIHDKEY INNER JOIN TWORK_INFO_PK_CNTR_DT PCD ON PD.CTKEY = PCD.CTKEY AND PD.OWKEY = PCD.OWKEY AND PD.PIHDKEY = PCD.PIHDKEY AND PD.PIDTKEY = PCD.PIDTKEY INNER JOIN TWORK_MST_CNTR CNTR ON PC.CTKEY = CNTR.CTKEY AND PC.CNTRBARCODE = CNTR.CNTRBARCODE INNER JOIN TWORK_MST_CTCD_DT CD ON CNTR.CTKEY = CD.CTKEY AND CNTR.CNTRDIVCD = CD.CTCDDTKEY AND CD.CTCDHDKEY = 'CNTRDIVCD' INNER JOIN TWORK_MST_ICBARCODE ICB ON PD.CTKEY = ICB.CTKEY AND PD.OWKEY = ICB.OWKEY AND PD.ICKEY = ICB.ICKEY WHERE WH.CTKEY = #{ctkey} AND WH.OWKEY = #{owkey} AND WH.WAHDDAY BETWEEN #{wkdayfr} AND #{wkdayto}
AND ICB.BARCODE = #{icbarcode}
GROUP BY WH.WAHDDAY , WH.WAHDNM , CD.CTCDDTNM , PC.CNTRBARCODE , PC.PIHDKEY

/* wms-outbound-obpckgprcs-sql-oracle.xml - selectWkCnlYn - WMS > 출고 관리 > 포장처리 - 작업취소여부 확인 */
SELECT CTKEY
	 , OWKEY
	 , OBHDKEY
	 , WKCNLREQYN
  FROM TWORK_INFO_OB_HD
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND OBHDKEY = #{obhdkey}
